#!/usr/bin/env python3
"""
HJATS 文件操作 MCP Server

解决 Cline 在 code-server 中因 WebSocket 断连导致 write_to_file 失败的问题。
通过 MCP 工具直接写文件，不依赖 VS Code 编辑器 API。

工具:
- write_file: 写入文件内容
- read_file: 读取文件内容
- edit_file: 用精确文本替换编辑文件
- run_cmd: 在 tmux 中执行命令（解决 pending 问题）
"""
import os
import sys
import json
import subprocess
import shutil
import tempfile
from datetime import datetime

from mcp.server import Server, NotificationOptions
from mcp.server.models import InitializationOptions
import mcp.server.stdio
import mcp.types as types

HJATS_PATH = "/home/ubuntu/HJATS"
WORKSPACE_PATH = "/home/ubuntu/.openclaw/workspace"


class HJATSFilesServer:
    def __init__(self):
        self.server = Server("hjats-files")

    def setup_handlers(self):
        self.server.list_tools()(self._list_tools)
        self.server.call_tool()(self._call_tool)

    async def _list_tools(self) -> list[types.Tool]:
        return [
            types.Tool(
                name="write_file",
                description="写入文件内容（替代 Cline 自带的 write_to_file，不受 WebSocket 断连影响）",
                inputSchema={
                    "type": "object",
                    "properties": {
                        "path": {
                            "type": "string",
                            "description": "文件路径（绝对路径或相对于项目根目录）",
                        },
                        "content": {
                            "type": "string",
                            "description": "文件内容",
                        },
                    },
                    "required": ["path", "content"],
                },
            ),
            types.Tool(
                name="read_file",
                description="读取文件内容",
                inputSchema={
                    "type": "object",
                    "properties": {
                        "path": {
                            "type": "string",
                            "description": "文件路径",
                        },
                    },
                    "required": ["path"],
                },
            ),
            types.Tool(
                name="edit_file",
                description="用精确文本替换编辑文件（类似 Cline 的 edit 操作）",
                inputSchema={
                    "type": "object",
                    "properties": {
                        "path": {
                            "type": "string",
                            "description": "文件路径",
                        },
                        "old_text": {
                            "type": "string",
                            "description": "要替换的原文（必须完全匹配，唯一）",
                        },
                        "new_text": {
                            "type": "string",
                            "description": "替换后的文本",
                        },
                    },
                    "required": ["path", "old_text", "new_text"],
                },
            ),
            types.Tool(
                name="run_cmd",
                description="在 tmux 中执行命令（不会因为 WebSocket 断连而卡住）",
                inputSchema={
                    "type": "object",
                    "properties": {
                        "command": {
                            "type": "string",
                            "description": "要执行的命令",
                        },
                        "cwd": {
                            "type": "string",
                            "description": "工作目录（默认 HJATS 根目录）",
                        },
                        "timeout": {
                            "type": "integer",
                            "description": "超时秒数（0=不超时，默认 300）",
                            "default": 300,
                        },
                    },
                    "required": ["command"],
                },
            ),
        ]

    async def _call_tool(self, name: str, arguments: dict) -> list[types.TextContent]:
        if name == "write_file":
            return self._write_file(arguments)
        elif name == "read_file":
            return self._read_file(arguments)
        elif name == "edit_file":
            return self._edit_file(arguments)
        elif name == "run_cmd":
            return self._run_cmd(arguments)
        raise ValueError(f"Unknown tool: {name}")

    def _resolve_path(self, path: str) -> str:
        """解析路径，支持相对路径和项目路径"""
        if os.path.isabs(path):
            return path
        # 尝试项目目录
        for base in [HJATS_PATH, WORKSPACE_PATH]:
            candidate = os.path.join(base, path)
            if os.path.exists(candidate):
                return candidate
        # 默认到 HJATS
        return os.path.join(HJATS_PATH, path)

    def _write_file(self, args: dict) -> list[types.TextContent]:
        path = self._resolve_path(args["path"])
        content = args["content"]
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, 'w') as f:
            f.write(content)
        size = os.path.getsize(path)
        return [types.TextContent(
            type="text",
            text=f"✅ 已写入 {path} ({size} bytes)"
        )]

    def _read_file(self, args: dict) -> list[types.TextContent]:
        path = self._resolve_path(args["path"])
        if not os.path.isfile(path):
            return [types.TextContent(type="text", text=f"文件不存在: {path}")]
        with open(path) as f:
            content = f.read()
        # 限制返回大小
        if len(content) > 100000:
            content = content[:100000] + "\n\n... (截断，文件过大)"
        return [types.TextContent(type="text", text=content)]

    def _edit_file(self, args: dict) -> list[types.TextContent]:
        path = self._resolve_path(args["path"])
        old_text = args["old_text"]
        new_text = args["new_text"]

        if not os.path.isfile(path):
            return [types.TextContent(type="text", text=f"文件不存在: {path}")]

        with open(path) as f:
            content = f.read()

        count = content.count(old_text)
        if count == 0:
            return [types.TextContent(type="text", text=f"❌ 未在文件中找到匹配的文本（区分大小写）")]
        if count > 1:
            return [types.TextContent(type="text", text=f"❌ 找到 {count} 处匹配，替换不唯一")]

        new_content = content.replace(old_text, new_text, 1)
        with open(path, 'w') as f:
            f.write(new_content)

        return [types.TextContent(
            type="text",
            text=f"✅ 已编辑 {path}（替换了 1 处）"
        )]

    def _run_cmd(self, args: dict) -> list[types.TextContent]:
        command = args["command"]
        cwd = args.get("cwd", HJATS_PATH)
        timeout = args.get("timeout", 300)

        # 确保 cwd 存在
        if not os.path.isdir(cwd):
            cwd = HJATS_PATH

        # 创建日志文件
        tag = datetime.now().strftime('%H%M%S')
        log_file = f"/tmp/hjats-run-{tag}.log"
        session_name = f"hjats-{tag}"

        # 创建执行脚本
        script = f"""#!/bin/bash
cd {cwd}
echo "[$(date '+%H:%M:%S')] 开始执行"
{command}
EXIT_CODE=$?
echo "[$(date '+%H:%M:%S')] 退出码: $EXIT_CODE"
exit $EXIT_CODE
"""
        script_path = f"/tmp/hjats-cmd-{tag}.sh"
        with open(script_path, 'w') as f:
            f.write(script)
        os.chmod(script_path, 0o755)

        # 在 tmux 中执行
        subprocess.run([
            "tmux", "new-session", "-d", "-s", session_name,
            f"{script_path} > {log_file} 2>&1"
        ], capture_output=True)

        # 等待命令完成或超时
        import time
        start = time.time()
        deadline = start + timeout if timeout > 0 else float('inf')

        while time.time() < deadline:
            # 检查 tmux 会话是否结束
            result = subprocess.run(
                ["tmux", "has-session", "-t", session_name],
                capture_output=True
            )
            if result.returncode != 0:
                break
            time.sleep(1)

        # 超时检查
        if time.time() >= deadline:
            # 终止会话
            subprocess.run(["tmux", "kill-session", "-t", session_name], capture_output=True)
            return [types.TextContent(
                type="text",
                text=f"⏰ 命令超时 ({timeout}s)\n查看日志: cat {log_file}"
            )]

        # 读取日志
        with open(log_file) as f:
            log_content = f.read()

        # 清理
        os.remove(script_path)

        return [types.TextContent(
            type="text",
            text=f"✅ 命令执行完毕\n日志: {log_file}\n\n{log_content}"
        )]

    async def run(self):
        async with mcp.server.stdio.stdio_server() as (read_stream, write_stream):
            await self.server.run(
                read_stream,
                write_stream,
                InitializationOptions(
                    server_name="hjats-files",
                    server_version="0.1.0",
                    capabilities={},
                ),
            )


if __name__ == "__main__":
    server = HJATSFilesServer()
    server.setup_handlers()
    import asyncio
    asyncio.run(server.run())
